  function typeNextWord() {
    if (i >= words.length) {
      cursor.remove();
      wrapper.textContent = text;
      if (callback) callback();
      return;
    }

    wrapper.textContent += (i > 0 ? ' ' : '') + words[i];
    i++;
    setTimeout(typeNextWord, speed);
