// elos/stargate/phase1.intentClassifier.js

/**
 * Intent Classifier: Analyze raw input to generate a diagnostic fingerprint
 * Includes language detection, tone tagging, complexity check, and special symbol triggers
 *
 * @param {string} input
 * @returns {object} diagnostic
 */
export function classifyIntent(input) {
  const trimmed = input.trim();
  const lang = detectLanguage(trimmed);
  const symbols = extractSymbolTriggers(trimmed);
  const tone = detectTone(trimmed);
  const complexity = estimateComplexity(trimmed);

  return {
    lang,
    tone,
    symbols,
    complexity,
    wordCount: trimmed.split(/\s+/).length,
    hasHebrew: /[֐-׿]/.test(trimmed),
    hasEnglish: /[a-zA-Z]/.test(trimmed),
  };
}

function detectLanguage(text) {
  if (/[֐-׿]/.test(text) && !/[a-zA-Z]/.test(text)) return "hebrew";
  if (/[a-zA-Z]/.test(text) && !/[֐-׿]/.test(text)) return "english";
  return "mixed";
}

function extractSymbolTriggers(text) {
  const triggers = [];
  if (text.includes("🔐")) triggers.push("private-mode");
  if (text.includes("✍️")) triggers.push("copy-polish");
  if (text.includes("⚡")) triggers.push("turbo-mode");
  return triggers;
}

function detectTone(text) {
  if (/!/.test(text)) return "urgent";
  if (/\?/.test(text)) return "inquisitive";
  return "neutral";
}

function estimateComplexity(text) {
  const sentences = text.split(/[.!?]/).length;
  const avgLength = text.split(/\s+/).length / sentences;
  if (avgLength > 20) return "high";
  if (avgLength > 10) return "medium";
  return "low";
}

// elos/stargate/phase2.precisionRewrite.js

/**
 * Phase 2 – Precision Rewrite
 * Core logic for structured prompt transformation
 * Powered by Stargate Protocol (v3.1-total-fireproofed)
 */

import { cleanInputText, normalizeSpacing, enforceClarityRules } from "../utils/fireproofingTools";

export function precisionRewrite(analysis) {
  if (!analysis || !analysis.intentType || !analysis.raw) {
    throw new Error("Missing analysis object or properties.");
  }

  let prompt = analysis.raw.trim();
  let rewrittenPrompt = prompt;

  // Apply precision edits based on intent
  switch (analysis.intentType) {
    case "instructional":
      rewrittenPrompt = prompt.replace(/^(please|can you)/i, "").trim();
      rewrittenPrompt = `Give step-by-step instructions: ${rewrittenPrompt}`;
      break;

    case "ideation":
      rewrittenPrompt = `Generate creative ideas for: ${prompt}`;
      break;

    case "rewrite":
      rewrittenPrompt = `Rewrite this clearly and concisely: ${prompt}`;
      break;

    case "diagnostic":
      rewrittenPrompt = `Analyze the following for tone, clarity, and logic gaps: ${prompt}`;
      break;

    case "strategic":
      rewrittenPrompt = `Respond like a strategist. Input: ${prompt}`;
      break;

    default:
      rewrittenPrompt = `Refine this prompt: ${prompt}`;
  }

  // Apply fireproofing utilities
  rewrittenPrompt = cleanInputText(rewrittenPrompt);
  rewrittenPrompt = normalizeSpacing(rewrittenPrompt);
  rewrittenPrompt = enforceClarityRules(rewrittenPrompt);

  return {
    original: prompt,
    rewritten: rewrittenPrompt,
    meta: {
      phase: "Precision Rewrite",
      timestamp: new Date().toISOString(),
      method: "rule-based with context overlay"
    }
  };
}

// File: /elos/stargate/phase3.postProcessing.js

import { runConstraintVerifier } from "../utils/constraintVerifier.js";
import { runConsistencyAudit } from "../utils/consistencyAudit.js";
import { runSelfDebug } from "../utils/selfDebug.js";

export async function postProcessPrompt(phaseTwoOutput, originalInput) {
  const { rewrittenPrompt, diagnostics } = phaseTwoOutput;

  // Phase 3.1: Run constraint enforcement
  const constraintReport = runConstraintVerifier(rewrittenPrompt);

  // Phase 3.2: Run tone/length/structure consistency audit
  const consistencyReport = runConsistencyAudit(rewrittenPrompt, originalInput);

  // Phase 3.3: Run internal debug check for anomalies or rewrite corruption
  const debugReport = runSelfDebug(rewrittenPrompt);

  return {
    finalPrompt: rewrittenPrompt,
    constraintReport,
    consistencyReport,
    debugReport,
    diagnostics,
    status: "Phase 3 Post-Processing Complete ✅"
  };
}

// /elos/stargate/stargate.kernel.js

import { classifyIntent } from './phase1.intentClassifier.js';
import { rewritePrompt } from './phase2.rewriteEngine.js';
import { postProcessPrompt } from './phase3.postProcessing.js';

export async function runStargateProtocol(userInput) {
  // Phase 1: Intent Classification + Diagnostic
  const intentData = classifyIntent(userInput);
  if (!intentData || !intentData.intent) {
    return {
      success: false,
      error: '❌ Intent could not be classified.',
    };
  }

  // Phase 2: Precision Rewrite
  const rewritten = rewritePrompt(userInput, intentData);
  if (!rewritten || typeof rewritten !== 'string') {
    return {
      success: false,
      error: '❌ Prompt rewrite failed.',
    };
  }

  // Phase 3: Post-Processing
  const finalized = postProcessPrompt(rewritten);
  if (!finalized || typeof finalized !== 'string') {
    return {
      success: false,
      error: '❌ Post-processing failed.',
    };
  }

  return {
    success: true,
    optimizedPrompt: finalized,
    metadata: {
      intent: intentData.intent,
      diagnostics: intentData.diagnostics,
    },
  };
}

// /elos/stargate/phase1.intentClassifier.js

export function classifyIntent(input) {
  const text = input.trim().toLowerCase();

  let intent = 'general';
  let diagnostics = [];

  if (/translate|rewrite|reword/.test(text)) {
    intent = 'translation';
    diagnostics.push('Detected translation-related keywords.');
  } else if (/summarize|tl;dr/.test(text)) {
    intent = 'summarization';
    diagnostics.push('Detected summarization-related keywords.');
  } else if (/generate|write|compose/.test(text)) {
    intent = 'generation';
    diagnostics.push('Detected generation-related keywords.');
  } else if (/debug|fix|repair/.test(text)) {
    intent = 'debugging';
    diagnostics.push('Detected debugging-related keywords.');
  } else {
    diagnostics.push('No specific keywords matched. Defaulting to general intent.');
  }

  return {
    intent,
    diagnostics,
  };
}

// /elos/stargate/phase2.rewriteEngine.js

export function rewritePrompt(input, { intent }) {
  const base = input.trim();

  // Simple rules per intent
  switch (intent) {
    case 'translation':
      return `Please translate the following text to clear, modern Hebrew:

${base}`;

    case 'summarization':
      return `Summarize the key points of the following content in bullet form:

${base}`;

    case 'generation':
      return `Write original content based on the following brief. Focus on clarity, engagement, and purpose:

${base}`;

    case 'debugging':
      return `Review the following prompt/code and identify issues or improvements:

${base}`;

    default:
      return `Rewrite the following for clarity, tone, and purpose:

${base}`;
  }
}

// /elos/stargate/phase3.postProcessing.js

export function postProcessPrompt(prompt) {
  let result = prompt;

  // Trim leading/trailing whitespace and normalize spacing
  result = result.trim().replace(/\s{3,}/g, '  ');

  // Ensure consistent punctuation spacing
  result = result.replace(/\s([,.!?])/g, '$1');
  result = result.replace(/([,.!?])(?=\S)/g, '$1 ');

  // Replace common lazy endings with clarity enforcement
  result = result.replace(/(etc\.|and so on)(?!\S)/gi, '');

  // Force sentence casing if single sentence
  if (!/[.!?]{2,}/.test(result)) {
    result = result.charAt(0).toUpperCase() + result.slice(1);
  }

  return result;
}

// /elos/dabroo/promptSurgery.js

import { classifyIntent } from '../stargate/phase1.intentClassifier.js';
import { rewritePrompt } from '../stargate/phase2.rewriteEngine.js';
import { finalizePrompt } from '../stargate/phase3.postProcessing.js';

const surgeryRules = [
  {
    pattern: /(?<!\w)write me a prompt(?!\w)/i,
    action: () => 'Generate a prompt template with persona, constraints, and output format.'
  },
  {
    pattern: /(?<!\w)make this better(?!\w)/i,
    action: () => 'Rewrite this prompt to be more specific, structured, and goal-driven.'
  },
  {
    pattern: /(?<!\w)translate this into(?!\w)/i,
    action: (match, input) => input.replace(/translate this into (\w+)/i, 'Rewrite the prompt in language: $1')
  }
  // Add more patterns as needed
];

export function runPromptSurgery(rawInput) {
  let surgicallyPatched = rawInput;

  for (const rule of surgeryRules) {
    if (rule.pattern.test(surgicallyPatched)) {
      const match = surgicallyPatched.match(rule.pattern);
      surgicallyPatched = typeof rule.action === 'function'
        ? rule.action(match, surgicallyPatched)
        : rule.action;
      break;
    }
  }

  const classified = classifyIntent(surgicallyPatched);
  const rewritten = rewritePrompt(surgicallyPatched, classified);
  const finalized = finalizePrompt(rewritten);

  return finalized;
}

