    "Process via TNF + Translate + Stargate chain",
    "Return output in native speaker tone-mirrored language"
  ],
  "fallback_logic": {
    "trigger_condition": "language not present in routing_map",
    "action": "default to native ChatGPT output",
    "log_event": true,
    "silent_fail": true
