# This file defines core modules powering collaborative prompt evolution in the ELos system

# 1. Dashboard Feed Engine
class FeedEngine:
    def __init__(self):
        self.trails = []

    def evaluate_trail(self, trail):
        score = 0
        if trail.fork_count >= 5:
            score += 2
        if trail.avg_rating >= 8.5:
            score += 2
        if trail.merges >= 3:
            score += 2
        if trail.updates_last_7d >= 3:
            score += 1
        if trail.bundle_uses >= 2:
            score += 1
        return score

    def promote(self, trails):
        promoted = [t for t in trails if self.evaluate_trail(t) >= 3]
        for trail in promoted:
            trail.status = "Promoted"
        return promoted


# 2. Trail Viewer
class TrailViewer:
    def __init__(self):
        self.trails = {}

    def show_history(self, prompt_id):
        return self.trails.get(prompt_id, [])

    def compare_versions(self, trail):
        return [(i, trail[i], trail[i+1]) for i in range(len(trail)-1)]


# 3. BundleForge
class BundleForge:
    def __init__(self):
        self.toolkits = {}

    def create_bundle(self, user_id, prompts):
        bundle_id = f"bundle_{len(self.toolkits)+1}"
        self.toolkits[bundle_id] = {"owner": user_id, "prompts": prompts}
        return bundle_id


# 4. Role Suggestor
class RoleSuggestor:
    def __init__(self, user_roles):
        self.user_roles = user_roles

    def suggest_trails(self, role):
        return [trail for trail in TrailDatabase if role in trail.tags]


# 5. Collab Bridge
class CollabBridge:
    def link_users(self, forked_prompt):
        return {
            "origin": forked_prompt.originator,
            "forked_by": forked_prompt.editor,
            "contributors": forked_prompt.contributors
        }


# 6. Trail Merge Resolver
class TrailMergeResolver:
    def merge_candidates(self, trail1, trail2):
        diff = calculate_diff_score(trail1, trail2)
        return diff >= 0.85


def calculate_diff_score(t1, t2):
    return sum(1 for i, j in zip(t1, t2) if i == j) / max(len(t1), len(t2))


# 7. Vault + Sync Tracker
class TrailVault:
    def __init__(self):
        self.history = {}

    def record_version(self, prompt_id, version):
        self.history.setdefault(prompt_id, []).append(version)

    def get_versions(self, prompt_id):
        return self.history.get(prompt_id, [])

    def enable_sync(self):
        return True  # External sync system auto-enabled


