        <li class="tab-link {% if forloop.first %}active{% endif %}" data-tab="tab-{{ forloop.index }}">
          {{ block.settings.tab_heading | strip_html }}
        </li>
      {% endfor %}
    </ul>

    <div class="tabs-content">
      {% for block in section.blocks %}
        <div id="tab-{{ forloop.index }}" class="tab-content {% if forloop.first %}active{% endif %}">
          {{ block.settings.tab_content }}
        </div>
      {% endfor %}
    </div>
  </div>
</section>

<script>
  document.addEventListener('DOMContentLoaded', function () {
    document.querySelectorAll('.product-tabs').forEach(function (section) {
      const tabs = section.querySelectorAll('.tab-link');
      const contents = section.querySelectorAll('.tab-content');

      tabs.forEach((tab) => {
        tab.addEventListener('click', function () {
          tabs.forEach(t => t.classList.remove('active'));
          this.classList.add('active');

          const target = this.dataset.tab;
          contents.forEach(c => c.classList.remove('active'));
          section.querySelector(`#${target}`).classList.add('active');
        });
      });
    });
  });
</script>

<style>
  .tabs-wrapper {
    margin-top: 2rem;
  }
  .tabs-nav {
    display: flex;
    flex-wrap: wrap;
    border-bottom: 1px solid #eee;
    gap: 2rem;
    justify-content: flex-start;
    list-style: none;
    padding: 0;
    margin: 0;
  }
  [dir="rtl"] .tabs-nav {
    justify-content: flex-end;
  }
  .tab-link {
    padding: 0.5rem 0;
    cursor: pointer;
    border-bottom: 2px solid transparent;
    font-weight: 500;
    color: #333;
    white-space: nowrap;
  }
  .tab-link.active {
    border-color: #000;
    font-weight: 700;
  }
  .tab-content {
    display: none;
    padding: 1rem 0;
    font-size: 0.95rem;
    line-height: 1.6;
    color: #444;
  }
  .tab-content.active {
    display: block;
  }
</style>

